{
  "domain_analysis": {
    "business_context": "Evolution of the Shipment aggregate from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental change to the core domain model of a delivery platform, affecting the Shipment aggregate root boundary, all downstream bounded contexts that consume shipment data, and external partner integrations. This is not a simple schema migration — it redefines what a Shipment *is*.",
    "bounded_context": "Shipment Management (core domain). Ripple effects into: Routing & Dispatch, Notifications, Billing, Partner Integration, and Reporting.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods being transported from an origin to one or more recipients. Post-change, a Shipment is a logical grouping that may involve multiple delivery stops." },
      { "term": "Recipient", "definition": "A party receiving a delivery, defined by name, address, phone number, and now also delivery preferences. A Recipient belongs to exactly one Shipment." },
      { "term": "Delivery Preference", "definition": "Recipient-level configuration such as preferred time window, safe-place instructions, signature requirement, or contactless delivery. Each Recipient on a Shipment may have distinct preferences." },
      { "term": "Primary Recipient", "definition": "The first or default recipient on a Shipment. Critical for backward compatibility — existing integrations and reports assume a single recipient and must resolve to this concept." },
      { "term": "Multi-stop Shipment", "definition": "A Shipment with more than one Recipient, requiring the platform to plan multiple delivery stops within a single shipment lifecycle." },
      { "term": "Shipment Status", "definition": "The lifecycle state of a Shipment. For multi-recipient shipments, this must now reconcile per-recipient delivery outcomes into an aggregate shipment-level status." },
      { "term": "Partner API Contract", "definition": "The external-facing data format consumed by partner systems. Currently assumes a single recipient per shipment." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A Shipment with zero recipients is logically undeliverable and represents corrupt state. There is no physical reality in which goods are shipped to nobody.",
      "testable_assertion": "Any attempt to create a Shipment with zero Recipients, or remove the last Recipient from an existing Shipment, MUST be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient MUST have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum fields required to physically deliver a package and contact the recipient. Without them, delivery is impossible and the data is incomplete.",
      "testable_assertion": "Creating or updating a Recipient with a null/empty name, address, or phone number MUST be rejected at the domain level."
    },
    {
      "id": "BR-3",
      "rule": "Delivery preferences are per-Recipient, not per-Shipment.",
      "invariant": true,
      "invariant_justification": "The entire point of multi-recipient support is that each recipient can have different delivery needs. Collapsing preferences to the shipment level defeats the business intent and corrupts the model.",
      "testable_assertion": "Each Recipient entity independently holds its own delivery preferences. Modifying one Recipient's preferences MUST NOT affect another Recipient on the same Shipment."
    },
    {
      "id": "BR-4",
      "rule": "Existing single-recipient shipments MUST remain fully functional and semantically identical after migration — they are multi-recipient shipments with exactly one recipient.",
      "invariant": true,
      "invariant_justification": "2 million production shipments cannot change meaning. The new model must be a strict superset of the old one. Any behavioral regression on existing data is a data integrity violation.",
      "testable_assertion": "All 2M existing shipments, when loaded under the new model, MUST return the same recipient data (name, address, phone) with no loss or transformation artifacts."
    },
    {
      "id": "BR-5",
      "rule": "A Shipment MUST expose a Primary Recipient for backward compatibility with partner APIs and legacy consumers.",
      "invariant": false,
      "invariant_justification": "This is a compatibility policy, not a physical constraint. The concept of 'primary' is a business decision that could evolve — e.g., partners could eventually adopt the multi-recipient format.",
      "testable_assertion": "Every Shipment, regardless of recipient count, MUST be able to resolve a single Primary Recipient. For migrated data, this is the original sole recipient. For new multi-recipient shipments, the creator must designate one."
    },
    {
      "id": "BR-6",
      "rule": "Shipment-level status must be derivable from individual per-recipient delivery outcomes.",
      "invariant": true,
      "invariant_justification": "If Recipient A's package is delivered but Recipient B's failed, the Shipment cannot simply be 'Delivered.' The aggregate status must faithfully represent reality or downstream systems (billing, SLA tracking) will operate on lies.",
      "testable_assertion": "A Shipment with at least one failed recipient delivery MUST NOT report an aggregate status of 'Delivered'. A Shipment is 'Delivered' only when ALL recipients have received their delivery."
    },
    {
      "id": "BR-7",
      "rule": "Recipients within a Shipment must be uniquely identifiable — no duplicate addresses on the same Shipment.",
      "invariant": false,
      "invariant_justification": "This is a data quality policy. There could be edge cases (different recipients at the same address, e.g., office building) where business may relax this. But by default, duplicate addresses on one shipment likely indicate user error.",
      "testable_assertion": "Adding a Recipient with an address identical to an existing Recipient on the same Shipment SHOULD raise a warning or require explicit confirmation."
    },
    {
      "id": "BR-8",
      "rule": "Delivery preferences have sensible defaults — a Recipient without explicit preferences MUST receive the platform's standard delivery behavior, not null/undefined behavior.",
      "invariant": true,
      "invariant_justification": "A Recipient with null delivery preferences is ambiguous and could cause driver confusion or failed deliveries. Defaults ensure every delivery attempt has clear instructions.",
      "testable_assertion": "A Recipient created without specifying delivery preferences MUST have the platform default preferences applied automatically."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The creator specifies two or more Recipients, each with distinct addresses and delivery preferences",
      "then": "The Shipment is created with all Recipients preserved, each with their own preferences, and a Primary Recipient is designated"
    },
    {
      "id": "AC-2",
      "given": "An existing single-recipient Shipment from production (pre-migration)",
      "when": "The Shipment is loaded under the new model",
      "then": "It has exactly one Recipient with the original name, address, and phone number. That Recipient is the Primary Recipient. No data is lost or transformed."
    },
    {
      "id": "AC-3",
      "given": "A multi-recipient Shipment exists",
      "when": "A partner API requests the Shipment data in the legacy format",
      "then": "The response contains the Primary Recipient's data in the original single-recipient schema. No breaking changes to the partner contract."
    },
    {
      "id": "AC-4",
      "given": "A Shipment with 3 Recipients where 2 are delivered and 1 has failed",
      "when": "The aggregate Shipment status is queried",
      "then": "The status reflects 'Partially Delivered' (or equivalent), NOT 'Delivered'"
    },
    {
      "id": "AC-5",
      "given": "A multi-recipient Shipment",
      "when": "A user attempts to remove the last remaining Recipient",
      "then": "The operation is rejected with a domain error — minimum one Recipient invariant is enforced"
    },
    {
      "id": "AC-6",
      "given": "A Shipment is being created",
      "when": "Zero Recipients are provided",
      "then": "Creation is rejected — the Shipment is never persisted"
    },
    {
      "id": "AC-7",
      "given": "A new Recipient is added to a Shipment without specifying delivery preferences",
      "when": "The Recipient is persisted",
      "then": "Platform default delivery preferences are applied to that Recipient"
    },
    {
      "id": "AC-8",
      "given": "A multi-recipient Shipment",
      "when": "Recipient B's delivery preference is updated to 'signature required'",
      "then": "Recipient A's delivery preferences remain unchanged"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A Shipment has 50 Recipients — what is the upper bound?",
      "expected_behavior": "The domain must define a maximum recipient count per Shipment. Without it, routing, billing, and dispatch complexity explode. Recommend a configurable upper bound (e.g., 10-20) enforced at the domain level."
    },
    {
      "scenario": "Two Recipients on the same Shipment have the same address but different names (e.g., roommates)",
      "expected_behavior": "This should be allowed but flagged as a potential duplicate. The driver should see both recipients listed for that stop."
    },
    {
      "scenario": "A Recipient is added to a Shipment that is already in-transit",
      "expected_behavior": "Domain must define at which lifecycle stages Recipient modification is allowed. Adding a recipient mid-transit has routing, billing, and SLA implications. Recommend: Recipients are immutable once the Shipment enters 'Dispatched' status."
    },
    {
      "scenario": "Partner API sends a webhook update for a multi-recipient Shipment, but only knows about single-recipient format",
      "expected_behavior": "The legacy webhook payload must reference the Primary Recipient. Partners must not receive confusing or incomplete data. New webhook format should be versioned (v2) and opt-in."
    },
    {
      "scenario": "All Recipients on a Shipment fail delivery",
      "expected_behavior": "Shipment status is 'Failed'. Return-to-sender or retry logic applies to the entire Shipment, not individual recipients — unless per-recipient retry is a supported workflow."
    },
    {
      "scenario": "Primary Recipient is removed from a multi-recipient Shipment",
      "expected_behavior": "A new Primary Recipient must be automatically designated (e.g., next by order) or the removal must be rejected until a new primary is assigned. The system must never be in a state with no Primary Recipient."
    },
    {
      "scenario": "Billing: is a multi-recipient Shipment one charge or N charges?",
      "expected_behavior": "This is a critical business decision that affects pricing, invoicing, and partner settlement. Must be defined before implementation. Each additional recipient likely incurs an additional delivery fee."
    },
    {
      "scenario": "Migration rollback — what if the new model needs to be reverted?",
      "expected_behavior": "Any Shipment created post-migration with multiple recipients cannot be represented in the old model. A rollback strategy must account for this: either prevent multi-recipient creation during a canary period, or accept that rollback loses new multi-recipient shipments."
    }
  ],

  "business_impact": {
    "financial": "Multi-recipient shipments introduce a new pricing dimension. Revenue opportunity if priced as premium feature. Risk of revenue leakage if billing is not updated to charge per-recipient delivery. Migration cost is non-trivial: 2M records to evolve, partner API versioning, and potential SLA penalties during transition.",
    "operational": "Routing and dispatch complexity increases significantly — a single shipment now represents a multi-stop route. Driver apps must display multiple stops per shipment. Warehouse ops must handle split-packing if different items go to different recipients. SLA tracking becomes per-recipient, increasing monitoring complexity.",
    "user": "Senders gain flexibility (e.g., one order with gifts to multiple people). Recipients gain personalized delivery preferences. However, tracking UX must be redesigned — 'Where is my package?' now has multiple answers per shipment. Confusion risk is high if the UX doesn't clearly separate per-recipient status.",
    "risk": "HIGH. This is a core model change with blast radius across every bounded context. Key risks: (1) Data migration failure on 2M records, (2) Partner API breakage causing integration failures, (3) Status aggregation bugs leading to incorrect SLA reporting, (4) Billing model not updated causing revenue leakage, (5) Rollback complexity if issues are discovered post-deploy.",
    "stakeholders_affected": [
      { "group": "Senders (Customers)", "impact": "New capability to send to multiple recipients in one shipment. Must understand new pricing model." },
      { "group": "Recipients", "impact": "Gain personalized delivery preferences. Tracking experience must be clear per-recipient." },
      { "group": "Drivers / Couriers", "impact": "Must handle multi-stop shipments. App UX must clearly show per-recipient delivery instructions and preferences." },
      { "group": "External Partners (API consumers)", "impact": "CRITICAL — existing integrations will break if not versioned properly. Must maintain backward-compatible v1 API while introducing v2." },
      { "group": "Billing / Finance Team", "impact": "Pricing model must be updated before launch. Multi-recipient billing logic must be defined and tested." },
      { "group": "Operations / Dispatch", "impact": "Route optimization algorithms must account for multi-stop shipments. Dispatch logic becomes more complex." },
      { "group": "Customer Support", "impact": "Must handle new scenarios: partial delivery disputes, per-recipient status inquiries, preference-related complaints." },
      { "group": "Data / Reporting Team", "impact": "All reports assuming 1:1 Shipment:Recipient must be updated. KPIs like 'delivery success rate' must account for partial delivery states." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec describes WHAT changes (1:N recipients with preferences) but leaves critical business decisions undefined: What are 'delivery preferences' exactly? What is the billing model? What is the max recipient count? When can recipients be modified in the shipment lifecycle? What does 'Partially Delivered' mean for SLA calculations? These are not implementation details — they are business rules that must be defined before any code is written. The partner API migration strategy is also unspecified.",
    "high_confidence_areas": [
      "The 1:N Recipient relationship and its structural implications",
      "Backward compatibility requirement for 2M existing shipments",
      "Need for Primary Recipient concept for partner API compatibility",
      "Per-recipient delivery preferences as independent entities",
      "Minimum one Recipient invariant"
    ],
    "low_confidence_areas": [
      "Exact composition of 'delivery preferences' — the spec says they exist but not what they contain",
      "Billing model for multi-recipient shipments — not addressed at all",
      "Lifecycle rules for when recipients can be added/removed/modified",
      "Maximum recipient count per shipment",
      "Aggregate shipment status derivation rules for partial delivery states",
      "Partner API migration timeline and versioning strategy"
    ],
    "assumptions": [
      "Delivery preferences include common options like time windows, signature requirements, and safe-place instructions — but this needs explicit definition",
      "The migration will be non-destructive and backward-compatible (additive schema change, not destructive)",
      "Partner APIs will continue to receive v1 format until explicitly migrated to v2",
      "A 'Primary Recipient' concept is acceptable as the backward-compatibility bridge"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec says each Recipient can have 'different delivery preferences' but does not define what delivery preferences are. This is a first-class domain concept that must be explicitly enumerated before implementation. Are we talking about time windows? Signature requirements? Contactless delivery? Safe-place instructions? All of the above? The answer affects the Recipient entity schema, the driver app UX, and the notification system.",
      "affected_stakeholders": ["Product Team", "Recipients", "Drivers", "Engineering"],
      "options": ["Define a fixed set of preference types now", "Define an extensible preference model that can grow", "Defer preferences to a follow-up and ship multi-recipient without them"],
      "recommendation": "Define a minimum viable set of preference types (time window, signature required, safe-place instructions, contactless) as an explicit enum or value object before implementation begins."
    },
    {
      "type": "missing_context",
      "description": "Billing model for multi-recipient shipments is completely unaddressed. Is it one charge with surcharges per additional recipient? Separate charges per recipient? Same price regardless? This directly affects revenue, partner settlement, and the Billing bounded context.",
      "affected_stakeholders": ["Finance Team", "Senders", "Partners", "Billing Engineering"],
      "options": ["Flat rate per shipment regardless of recipients", "Base rate + per-additional-recipient surcharge", "Per-recipient pricing"],
      "recommendation": "Must be defined by Finance/Product before launch. Recommend base rate + per-additional-recipient surcharge as it incentivizes the feature while covering marginal delivery cost."
    },
    {
      "type": "ambiguity",
      "description": "Partner API migration strategy is undefined. ~2M shipments are consumed by external partners in single-recipient format. What is the plan? API versioning? Deprecation timeline? Will partners be required to migrate? What happens to webhooks?",
      "affected_stakeholders": ["External Partners", "Partner Integration Team", "Engineering"],
      "options": ["Maintain v1 API indefinitely with Primary Recipient mapping", "Version the API (v2) and give partners a migration window", "Dual-write: send both v1 and v2 payloads during transition"],
      "recommendation": "Introduce v2 API alongside v1. V1 returns Primary Recipient only and is maintained for at least 12 months. Partners opt into v2 on their timeline."
    },
    {
      "type": "missing_context",
      "description": "Shipment lifecycle rules for recipient modification are undefined. Can recipients be added after the shipment is dispatched? After pickup? Only during creation? This has massive routing, SLA, and operational implications.",
      "affected_stakeholders": ["Operations", "Drivers", "Senders", "Engineering"],
      "options": ["Recipients immutable after creation", "Recipients modifiable until dispatch", "Recipients modifiable at any time with re-routing"],
      "recommendation": "Recipients should be modifiable only before the Shipment enters 'Dispatched' status. Post-dispatch modification is a separate, more complex feature that should not be in scope for v1."
    }
  ],

  "rejection_reasons": []
}

